-- ═══════════════════════════════════════════════════════════════
-- aihkya.com - AI Tools Discovery Platform
-- Complete Seed Database v2.0 - 100 Tools, 14 Tables
-- Generated: 2026-02-25
-- ═══════════════════════════════════════════════════════════════


-- Enable extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Categories
CREATE TABLE IF NOT EXISTS categories (
    id SERIAL PRIMARY KEY,
    name VARCHAR(100) NOT NULL UNIQUE,
    slug VARCHAR(100) NOT NULL UNIQUE,
    icon VARCHAR(50),
    display_order INT DEFAULT 0,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Sub-categories
CREATE TABLE IF NOT EXISTS sub_categories (
    id SERIAL PRIMARY KEY,
    category_id INT REFERENCES categories(id) ON DELETE CASCADE,
    name VARCHAR(100) NOT NULL,
    slug VARCHAR(100) NOT NULL UNIQUE,
    description TEXT,
    icon VARCHAR(50),
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Tools (all 25+ fields)
CREATE TABLE IF NOT EXISTS tools (
    id SERIAL PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    slug VARCHAR(200) NOT NULL UNIQUE,
    description_en TEXT,
    description_hi TEXT,
    detailed_description_en TEXT,
    category VARCHAR(100) NOT NULL,
    sub_category VARCHAR(100),
    tags TEXT[] DEFAULT '{}',
    pricing_model VARCHAR(20) CHECK (pricing_model IN ('Free','Freemium','Paid')),
    free_tier_details TEXT,
    price_usd_monthly DECIMAL(10,2) DEFAULT 0,
    price_inr_monthly DECIMAL(10,2) DEFAULT 0,
    website_url TEXT,
    youtube_hindi_url TEXT,
    platform VARCHAR(200),
    ai_model VARCHAR(200),
    io_type VARCHAR(200),
    language_support VARCHAR(200),
    best_for_india TEXT,
    rating DECIMAL(2,1) DEFAULT 0 CHECK (rating >= 0 AND rating <= 5),
    logo_url TEXT,
    screenshots TEXT[] DEFAULT '{}',
    api_available BOOLEAN DEFAULT FALSE,
    api_docs_url TEXT,
    privacy_summary TEXT,
    alternatives TEXT[] DEFAULT '{}',
    integrations TEXT[] DEFAULT '{}',
    review_count INT DEFAULT 0,
    is_featured BOOLEAN DEFAULT FALSE,
    is_sponsored BOOLEAN DEFAULT FALSE,
    is_verified BOOLEAN DEFAULT TRUE,
    status VARCHAR(20) DEFAULT 'published' CHECK (status IN ('draft','published','disabled')),
    date_added DATE DEFAULT CURRENT_DATE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Users
CREATE TABLE IF NOT EXISTS users (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    email VARCHAR(255) UNIQUE,
    phone VARCHAR(20) UNIQUE,
    name VARCHAR(200),
    avatar_url TEXT,
    language_pref VARCHAR(10) DEFAULT 'hi' CHECK (language_pref IN ('hi','en','both')),
    role VARCHAR(20) DEFAULT 'user' CHECK (role IN ('user','admin','moderator')),
    onboarding_complete BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- User Preferences
CREATE TABLE IF NOT EXISTS user_preferences (
    id SERIAL PRIMARY KEY,
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    category_id INT REFERENCES categories(id) ON DELETE CASCADE,
    notification_enabled BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, category_id)
);

-- Reviews
CREATE TABLE IF NOT EXISTS reviews (
    id SERIAL PRIMARY KEY,
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    tool_id INT REFERENCES tools(id) ON DELETE CASCADE,
    rating INT CHECK (rating >= 1 AND rating <= 5),
    review_text TEXT,
    is_verified BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, tool_id)
);

-- Bookmarks
CREATE TABLE IF NOT EXISTS bookmarks (
    id SERIAL PRIMARY KEY,
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    tool_id INT REFERENCES tools(id) ON DELETE CASCADE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, tool_id)
);

-- Tool Clicks
CREATE TABLE IF NOT EXISTS tool_clicks (
    id SERIAL PRIMARY KEY,
    tool_id INT REFERENCES tools(id) ON DELETE CASCADE,
    user_id UUID,
    click_type VARCHAR(20) CHECK (click_type IN ('visit','youtube','bookmark','compare','share')),
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Notifications
CREATE TABLE IF NOT EXISTS notifications (
    id SERIAL PRIMARY KEY,
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    type VARCHAR(30) CHECK (type IN ('new_tool','price_change','weekly_digest','booking','system')),
    title VARCHAR(300),
    body TEXT,
    read BOOLEAN DEFAULT FALSE,
    tool_id INT REFERENCES tools(id) ON DELETE SET NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Bookings
CREATE TABLE IF NOT EXISTS bookings (
    id SERIAL PRIMARY KEY,
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    service_tier VARCHAR(30) CHECK (service_tier IN ('quick_help','full_setup','automation_package')),
    amount_inr DECIMAL(10,2),
    payment_id VARCHAR(200),
    razorpay_order_id VARCHAR(200),
    status VARCHAR(20) DEFAULT 'pending' CHECK (status IN ('pending','confirmed','completed','cancelled','refunded')),
    scheduled_at TIMESTAMPTZ,
    meeting_url TEXT,
    notes TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Tool Comparisons
CREATE TABLE IF NOT EXISTS tool_comparisons (
    id SERIAL PRIMARY KEY,
    tool_id_1 INT REFERENCES tools(id) ON DELETE CASCADE,
    tool_id_2 INT REFERENCES tools(id) ON DELETE CASCADE,
    comparison_text TEXT,
    winner_tool_id INT REFERENCES tools(id) ON DELETE SET NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(tool_id_1, tool_id_2)
);

-- Sponsored Listings
CREATE TABLE IF NOT EXISTS sponsored_listings (
    id SERIAL PRIMARY KEY,
    tool_id INT REFERENCES tools(id) ON DELETE CASCADE,
    sponsor_name VARCHAR(200),
    start_date DATE,
    end_date DATE,
    amount_paid DECIMAL(10,2),
    placement_type VARCHAR(30) CHECK (placement_type IN ('homepage_featured','category_top','search_promoted','banner')),
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Data Sources
CREATE TABLE IF NOT EXISTS data_sources (
    id SERIAL PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    source_type VARCHAR(30) CHECK (source_type IN ('RSS','API','Scraper','Manual','Directory')),
    url TEXT,
    description TEXT,
    update_frequency VARCHAR(50),
    cost VARCHAR(100),
    auto_importable BOOLEAN DEFAULT FALSE,
    is_active BOOLEAN DEFAULT TRUE,
    last_fetched_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Admin Audit Log
CREATE TABLE IF NOT EXISTS admin_audit_log (
    id SERIAL PRIMARY KEY,
    admin_id UUID REFERENCES users(id) ON DELETE SET NULL,
    action VARCHAR(50) NOT NULL,
    entity_type VARCHAR(50),
    entity_id INT,
    details JSONB,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_tools_category ON tools(category);
CREATE INDEX IF NOT EXISTS idx_tools_sub_category ON tools(sub_category);
CREATE INDEX IF NOT EXISTS idx_tools_pricing ON tools(pricing_model);
CREATE INDEX IF NOT EXISTS idx_tools_rating ON tools(rating DESC);
CREATE INDEX IF NOT EXISTS idx_tools_status ON tools(status);
CREATE INDEX IF NOT EXISTS idx_tools_tags ON tools USING GIN(tags);
CREATE INDEX IF NOT EXISTS idx_tools_date ON tools(date_added DESC);
CREATE INDEX IF NOT EXISTS idx_tools_featured ON tools(is_featured) WHERE is_featured = TRUE;
CREATE INDEX IF NOT EXISTS idx_reviews_tool ON reviews(tool_id);
CREATE INDEX IF NOT EXISTS idx_reviews_user ON reviews(user_id);
CREATE INDEX IF NOT EXISTS idx_bookmarks_user ON bookmarks(user_id);
CREATE INDEX IF NOT EXISTS idx_clicks_tool ON tool_clicks(tool_id);
CREATE INDEX IF NOT EXISTS idx_clicks_date ON tool_clicks(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_notifications_user ON notifications(user_id);
CREATE INDEX IF NOT EXISTS idx_notifications_unread ON notifications(user_id) WHERE read = FALSE;
CREATE INDEX IF NOT EXISTS idx_bookings_user ON bookings(user_id);
CREATE INDEX IF NOT EXISTS idx_bookings_status ON bookings(status);


