-- ═══ VERIFICATION ═══
SELECT 'Total tools: ' || COUNT(*) FROM tools;
SELECT 'By category: ' || category || ' = ' || COUNT(*) FROM tools GROUP BY category ORDER BY COUNT(*) DESC;
SELECT 'By pricing: ' || pricing_model || ' = ' || COUNT(*) FROM tools GROUP BY pricing_model;
SELECT 'Tools with Hindi desc: ' || COUNT(*) FROM tools WHERE description_hi IS NOT NULL AND description_hi != '';
SELECT 'Tools with alternatives: ' || COUNT(*) FROM tools WHERE array_length(alternatives, 1) > 0;
SELECT 'Tools with logo: ' || COUNT(*) FROM tools WHERE logo_url IS NOT NULL AND logo_url != '';
SELECT 'Total tables: ' || COUNT(*) FROM information_schema.tables WHERE table_schema = 'public';
